```go
package main

import (
	"database/sql"
	"fmt"
	"strings"

	_ "github.com/go-sql-driver/mysql" // Import MySQL driver
)

type Customer struct {
	ID        int
	Name      string
	Status    string
	City      string
	SignupYear int
}

func FindCustomers(db *sql.DB, filters map[string]string) ([]Customer, error) {
	var customers []Customer
	query := "SELECT ID, Name, Status, City, SignupYear FROM customers"
	args := make([]interface{}, 0)
	whereClauses := make([]string, 0)

	for key, value := range filters {
		switch key {
		case "status":
			whereClauses = append(whereClauses, fmt.Sprintf("Status = ?"))
			args = append(args, value)
		case "city":
			whereClauses = append(whereClauses, fmt.Sprintf("City = ?"))
			args = append(args, value)
		case "signup_year":
			whereClauses = append(whereClauses, fmt.Sprintf("SignupYear = ?"))
			args = append(args, value)
		default:
			return nil, fmt.Errorf("invalid filter key: %s", key)
		}
	}

	if len(whereClauses) > 0 {
		query += " WHERE " + strings.Join(whereClauses, " AND ")
	}

	rows, err := db.Query(query, args...)
	if err != nil {
		return nil, err
	}
	defer rows.Close()

	for rows.Next() {
		var customer Customer
		err := rows.Scan(&customer.ID, &customer.Name, &customer.Status, &customer.City, &customer.SignupYear)
		if err != nil {
			return nil, err
		}
		customers = append(customers, customer)
	}

	if err := rows.Err(); err != nil {
		return nil, err
	}

	return customers, nil
}

func main() {
	// Example usage
	db, err := sql.Open("mysql", "user:password@tcp(127.0.0.1:3306)/dbname")
	if err != nil {
		panic(err)
	}
	defer db.Close()

	filters := map[string]string{
		"status":    "active",
		"city":      "New York",
		"signup_year": "2020",
	}

	customers, err := FindCustomers(db, filters)
	if err != nil {
		panic(err)
	}

	for _, customer := range customers {
		fmt.Printf("Customer: %+v\n", customer)
	}
}
