	ID    int
	Order string
}

// GetOrdersByIDs retrieves all rows from the orders table whose ID is in the given slice of IDs.
func GetOrdersByIDs(db *sql.DB, orderIDs []int) ([]Order, error) {
	if len(orderIDs) == 0 {
		return []Order{}, nil
	}

	// Create a placeholder for each ID in the IN clause
placeholders := make([]string, len(orderIDs))
	for i := range orderIDs {
		placeholders[i] = "?"
	}

	// Join placeholders with commas to form the IN clause
	inClause := fmt.Sprintf("(%s)", strings.Join(placeholders, ", "))

	// Prepare the SQL query
	query := `SELECT id, order FROM orders WHERE id IN ` + inClause

	// Execute the query
	rows, err := db.Query(query, orderIDs...)
	if err != nil {
		return nil, err
	}
	defer rows.Close()

	// Scan the results into Order structs
	var orders []Order
	for rows.Next() {
		var order Order
		err := rows.Scan(&order.ID, &order.Order)
		if err != nil {
			return nil, err
		}
		orders = append(orders, order)
	}

	// Check for errors from iterating over rows
	if err := rows.Err(); err != nil {
		return nil, err
	}

	return orders, nil
}

func main() {
