```go
func getOrdersByIDs(db *sql.DB, ids []int) ([]map[string]interface{}, error) {
    if len(ids) == 0 {
        return nil, fmt.Errorf("no IDs provided")
    }

    // Create a placeholder string for each ID in the slice
    placeholders := make([]string, len(ids))
    for i := range ids {
        placeholders[i] = "?"
    }

    // Join the placeholders with commas to form the IN clause
    inClause := fmt.Sprintf("(%s)", strings.Join(placeholders, ", "))

    // Prepare the SQL query
    query := `SELECT * FROM orders WHERE id IN ` + inClause

    // Execute the query
    rows, err := db.Query(query, ids...)
    if err != nil {
        return nil, err
    }
    defer rows.Close()

    // Get column names
    columns, err := rows.Columns()
    if err != nil {
        return nil, err
    }

    // Prepare a slice to hold the results
    var result []map[string]interface{}

    for rows.Next() {
        // Create a slice to hold the values of each row
        values := make([]interface{}, len(columns))
        valuePointers := make([]interface{}, len(columns))

        for i := range columns {
            valuePointers[i] = &values[i]
        }

        // Scan the row into the value pointers
        if err := rows.Scan(valuePointers...); err != nil {
            return nil, err
        }

        // Create a map to hold the column-value pairs
        rowMap := make(map[string]interface{})
        for i, colName := range columns {
            val := values[i]
            b, ok := val.([]byte)
            if ok {
                rowMap[colName] = string(b)
            } else {
                rowMap[colName] = val
            }
        }

        // Append the map to the result slice
        result = append(result, rowMap)
    }

    return result, nil
}
