package main

import (
    "database/sql"
    "fmt"
    "log"

    _ "github.com/lib/pq"
)

// Order represents an order in the database.
type Order struct {
    ID          int
    CustomerID  string
    TotalAmount float64
    Status      string
}

// FetchOrdersByID fetches orders from the database by their IDs.
func FetchOrdersByID(db *sql.DB, ids []int) ([]Order, error) {
    if len(ids) == 0 {
        return nil, fmt.Errorf("no order IDs provided")
    }

    // Create a placeholder for each ID
    placeholders := make([]string, len(ids))
    for i := range ids {
        placeholders[i] = "?"
    }

    query := fmt.Sprintf("SELECT id, customer_id, total_amount, status FROM orders WHERE id IN (%s)", strings.Join(placeholders, ", "))

    rows, err := db.Query(query, ids...)
    if err != nil {
        return nil, err
    }
    defer rows.Close()

    var orders []Order
    for rows.Next() {
        var order Order
        if err := rows.Scan(&order.ID, &order.CustomerID, &order.TotalAmount, &order.Status); err != nil {
            return nil, err
        }
        orders = append(orders, order)
    }

    if err := rows.Err(); err != nil {
        return nil, err
    }

    return orders, nil
}

