```go
package main

import (
	"database/sql"
	"fmt"
	"log"

	_ "github.com/lib/pq"  // Import the PostgreSQL driver
	// or
	// _ "github.com/go-sql-driver/mysql"  // Import the MySQL driver
)

type User struct {
	ID    int
	Name  string
	Email string
}

func insertUser(db *sql.DB, userMap map[string]interface{}) (int64, error) {
	// Prepare the SQL query to insert a new user
	query := "INSERT INTO users (name, email) VALUES ($1, $2) RETURNING id"

	// Extract values from the map
	name, okName := userMap["name"].(string)
	email, okEmail := userMap["email"].(string)

	if !okName || !okEmail {
		return 0, fmt.Errorf("invalid data types in userMap")
	}

	var userID int64
	err := db.QueryRow(query, name, email).Scan(&userID)
	if err != nil {
		return 0, err
	}

	return userID, nil
}

func main() {
	// Connect to the database (replace with your connection string)
	connStr := "user=your_user dbname=your_db sslmode=disable"
	db, err := sql.Open("postgres", connStr)  // For PostgreSQL
	// or
	// db, err := sql.Open("mysql", connStr)  // For MySQL
	if err != nil {
		log.Fatal(err)
	}
	defer db.Close()

	// Test the connection
	err = db.Ping()
	if err != nil {
		log.Fatal(err)
	}

	// Example user map
	userMap := map[string]interface{}{
		"name":  "John Doe",
		"email": "john.doe@example.com",
	}

	// Insert the new user and get the new ID
	newUserID, err := insertUser(db, userMap)
	if err != nil {
		log.Fatal(err)
	}

	fmt.Printf("New user inserted with ID: %d\n", newUserID)
}
