Sure! Below is a simple example of how you can create a function to handle inserting a new user into a `users` table using Go's `database/sql` package. This example assumes you have already set up your database connection and that the `users` table has columns like `id`, `username`, `email`, and `password`.

```go
package main

import (
	"database/sql"
	"fmt"
	"log"

	_ "github.com/go-sql-driver/mysql" // Import MySQL driver
)

// User represents a user in the database.
type User struct {
	ID       int    `json:"id"`
	Username string `json:"username"`
	Email    string `json:"email"`
	Password string `json:"password"`
}

// InsertUser inserts a new user into the users table.
func InsertUser(db *sql.DB, user User) error {
	query := "INSERT INTO users (username, email, password) VALUES (?, ?, ?)"
	_, err := db.Exec(query, user.Username, user.Email, user.Password)
	if err != nil {
		return fmt.Errorf("failed to insert user: %w", err)
	}
	return nil
}

func main() {
	// Set up your database connection
	db, err := sql.Open("mysql", "user:password@tcp(127.0.0.1:3306)/dbname")
	if err != nil {
		log.Fatalf("failed to connect to database: %v", err)
	}
	defer db.Close()

	// Example user data from a signup POST
	user := User{
		Username: "newuser",
		Email:    "newuser@example.com",
		Password: "password123",
	}

	// Insert the new user into the database
	err = InsertUser(db, user)
	if err != nil {
		log.Fatalf("failed to insert user: %v", err)
	}

	fmt.Println("User inserted successfully!")
}
```

### Explanation:
1. **Database Connection**: The `sql.Open` function is used to establish a connection to the MySQL database.
