type User struct {
	ID    int
	Name  string
	Email string
}

// GetUserByEmail retrieves a user from the users table by email.
func GetUserByEmail(db *sql.DB, email string) (*User, error) {
	query := "SELECT id, name, email FROM users WHERE email = ?"
	var user User

