```

Now, here's the Rust code for the function:

```rust
use sqlx::postgres::PgPool;
use std::collections::HashMap;

#[derive(Debug)]
struct Customer {
    id: i32,
    name: String,
    status: String,
    city: String,
    signup_year: i32,
}

async fn get_customers(pool: &PgPool, filters: HashMap<&str, &str>) -> Result<Vec<Customer>, sqlx::Error> {
    let mut query = "SELECT id, name, status, city, signup_year FROM customers".to_string();
    let mut params = Vec::new();

    if let Some(status) = filters.get("status") {
        query.push_str(" WHERE status = $1");
        params.push(status);
    }

    if let Some(city) = filters.get("city") {
        if query.contains("WHERE") {
            query.push_str(" AND city = $2");
        } else {
            query.push_str(" WHERE city = $1");
        }
        params.push(city);
    }

    if let Some(signup_year) = filters.get("signup_year") {
        if query.contains("WHERE") {
            query.push_str(" AND signup_year = $3");
        } else {
            query.push_str(" WHERE signup_year = $1");
        }
        params.push(signup_year);
    }

    let customers: Vec<Customer> = sqlx::query_as(&query)
        .bind(params)
        .fetch_all(pool)
        .await?;

    Ok(customers)
}

