```go
package main

import (
	"database/sql"
	"fmt"
	"log"

	"github.com/jmoiron/sqlx"
)

type Customer struct {
	ID        int    `db:"id"`
	Name      string `db:"name"`
	Status    string `db:"status"`
	City      string `db:"city"`
	SignupYear int    `db:"signup_year"`
}

func fetchCustomers(db *sqlx.DB, filters map[string]interface{}) ([]Customer, error) {
	var customers []Customer
	query := "SELECT id, name, status, city, signup_year FROM customers WHERE 1=1"

	for key, value := range filters {
		query += fmt.Sprintf(" AND %s = ?", key)
	}

	err := db.Select(&customers, query, sql.NamedArgs(filters))
	if err != nil {
		return nil, err
	}

	return customers, nil
}

func main() {
	db, err := sqlx.Connect("postgres", "user=your_user dbname=your_db sslmode=disable")
	if err != nil {
		log.Fatal(err)
	}
	defer db.Close()

	filters := map[string]interface{}{
		"status": "active",
		"city":   "Berlin",
	}

	customers, err := fetchCustomers(db, filters)
	if err != nil {
		log.Fatal(err)
	}

	for _, customer := range customers {
		fmt.Printf("Customer: %+v\n", customer)
	}
}
```

