```rust
use rusqlite::{Connection, Result, Row};

fn get_orders_by_ids(conn: &Connection, order_ids: &[i64]) -> Result<Vec<Order>> {
    if order_ids.is_empty() {
        return Ok(vec![]);
    }

    let mut stmt = conn.prepare(
        "SELECT id, customer_id, product_id, quantity, price FROM orders WHERE id IN (?1)",
    )?;

    // Create a vector of parameters for the IN clause
    let params: Vec<rusqlite::types::ToSql> = order_ids.iter().cloned().collect();

    let rows = stmt.query_map(params.as_slice(), |row| {
        Ok(Order {
            id: row.get(0)?,
            customer_id: row.get(1)?,
            product_id: row.get(2)?,
            quantity: row.get(3)?,
            price: row.get(4)?,
        })
    })?;

    let mut orders = Vec::new();
    for row in rows {
        orders.push(row?);
    }

    Ok(orders)
}

// Define the Order struct to match the structure of your database table
