    let conn = Connection::open("example.db")?;

    // Example order IDs
    let order_ids = vec![1, 2, 3];

    let orders = get_orders_by_ids(&conn, &order_ids)?;

    for order in orders {
        println!("{:?}", order);
    }

    Ok(())
}
```

