use rusqlite::{Connection, Result};
use std::collections::HashMap;

fn create_user_from_form(conn: &Connection, form: &HashMap<String, String>) -> Result<i64> {
    // Extract the email and name from the form data
    let email = form.get("email").ok_or(rusqlite::Error::InvalidParameterName)?;
    let name = form.get("name").ok_or(rusqlite::Error::InvalidParameterName)?;

    // Prepare the SQL statement to insert a new user
    let sql = "INSERT INTO users (name, email) VALUES (?1, ?2)";

    // Execute the SQL statement and get the last inserted row ID
    let id: i64 = conn.execute(sql, [&name, &email])?;

    Ok(id)
}

fn main() -> Result<()> {
    // Open a connection to the SQLite database
    let conn = Connection::open("example.db")?;

    // Create the users table if it doesn't exist
    conn.execute(
        "CREATE TABLE IF NOT EXISTS users (
            id INTEGER PRIMARY KEY AUTOINCREMENT,
            name TEXT NOT NULL,
            email TEXT NOT NULL UNIQUE
        )",
        [],
    )?;

    // Example form data
    let mut form = HashMap::new();
    form.insert("name".to_string(), "John Doe".to_string());
    form.insert("email".to_string(), "john.doe@example.com".to_string());

    // Insert the user into the database and get the new row ID
    let user_id = create_user_from_form(&conn, &form)?;
    println!("New user inserted with ID: {}", user_id);

    Ok(())
}
