use rusqlite::{params, Connection, Result};
use serde::Serialize;

#[derive(Serialize)]
struct Product {
    id: i32,
    name: String,
    price: f64,
    created_at: chrono::NaiveDateTime,
}

fn get_sorted_products(conn: &Connection, sort_by: &str) -> Result<Vec<Product>> {
    let mut stmt = conn.prepare(
        "SELECT id, name, price, created_at FROM products ORDER BY $1",
    )?;

    // Bind the sort column to the statement
    let rows = stmt.query_map(params![sort_by], |row| {
        Ok(Product {
            id: row.get(0)?,
            name: row.get(1)?,
            price: row.get(2)?,
            created_at: row.get(3)?,
        })
    })?;

    // Collect the results into a vector
    let mut products = Vec::new();
    for row in rows {
        products.push(row?);
    }

    Ok(products)
}

fn main() -> Result<()> {
    // Example usage
    let conn = Connection::open("example.db")?;

    // Assuming you have a sort parameter from the query string, e.g., "name"
    let sort_by = "name";

    let products = get_sorted_products(&conn, sort_by)?;

    for product in products {
        println!("{:?}", product);
    }

    Ok(())
}
