struct User {
    id: i32,
    email: String,
    password_hash: String,
}

async fn get_user_by_email(conn: web::Data<Connection>, email: web::Path<String>) -> HttpResponse {
    match get_user(&conn, &email) {
        Ok(Some(user)) => HttpResponse::Ok().json(user),
        Ok(None) => HttpResponse::NotFound().body("User not found"),
        Err(e) => HttpResponse::InternalServerError().body(format!("Database error: {}", e)),
    }
}

fn get_user(conn: &Connection, email: &str) -> Result<Option<User>> {
    let mut stmt = conn.prepare("SELECT id, email, password_hash FROM users WHERE email = ?")?;
    let user_opt = stmt.query_row(params![email], |row| {
        Ok(User {
            id: row.get(0)?,
            email: row.get(1)?,
            password_hash: row.get(2)?,
        })
    })?;

    match user_opt {
        rusqlite::OptionalRow::Some(user) => Ok(Some(user)),
        rusqlite::OptionalRow::None => Ok(None),
    }
}

